Create client/index.js:
import React from 'react';
import './styles';
import { hydrateRoot } from 'react-dom/client';
import { loadableReady } from '@loadable/component';
import { Provider } from 'react-redux';
import { RouterProvider } from '@tata1mg/router';
import { HelmetProvider } from 'react-helmet-async';
import clientRouter from 'catalyst-core/router/ClientRouter';
import WebBridge from 'catalyst-core/WebBridge';
import configureStore from '@store';

window.addEventListener('load', () => {
  loadableReady(() => {
    const { __ROUTER_INITIAL_DATA__: routerInitialData, __INITIAL_STATE__ } = window;
    const store = configureStore(__INITIAL_STATE__ || {});
    const router = clientRouter({ store, routerInitialState: routerInitialData });
    const Application = (
      <Provider store={store} serverState={__INITIAL_STATE__}>
        <HelmetProvider>
          <React.StrictMode>
            <RouterProvider router={router} />
          </React.StrictMode>
        </HelmetProvider>
      </Provider>
    );
    WebBridge.init();
    const container = document.getElementById('app');
    hydrateRoot(container, Application);
  });
});

Create client/styles.js: import '../src/styles/global.css' (adjust path to your global stylesheet).

CRITICAL: WebBridge.init() must be called before hydrateRoot — it registers native bridge event handlers. Missing this call means no JS-to-native communication (postMessage, camera, file picker, haptics all break silently on device).
